insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('modality', 'Modality', '', '', ARRAY['modality','input modality','output modality','sensory mode']::text[], 'Core', 'A type of input or output - text, image, audio, video - that the model can process or produce.', 'Like your five senses: sight, hearing, touch, taste, smell. Each is a different modality, each carries unique information.', 'GPT-4 Vision accepts both text and image modalities as input. A music generation model outputs audio. Multimodal models work across several at once.', '[]'::jsonb, 'Models are trained on specific modalities that match their training data and architecture. Fusing modalities - combining text + image, for instance - requires careful alignment so the model learns to reason across them. Each modality has different dimensionality and structure: text is discrete tokens, images are spatial, audio is temporal.', 'Expanding to new modalities (video, audio) unlocks new use cases and markets, but raises development and training cost.', 'Modality support requires specialized encoders/decoders and often separate embedding spaces that must be bridged.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('visualquestionanswering', 'Visual Question Answering', '', '', ARRAY['visual question answering','image QA','visual reasoning']::text[], 'Core', 'The task of answering natural-language questions about images - combining vision and language understanding.', 'Like a student pointing to a diagram in a textbook and asking "what color is this?" The model sees the image and understands the question.', '"What color is the car?" while shown a photo. "How many people are in this room?" over a screenshot. "Is the dog sitting?" - yes or no.', '[]'::jsonb, 'VQA requires grounding language in visual content: parsing the question, locating relevant image regions, and fusing visual features with textual semantics. Biases in datasets (e.g., yes/no imbalance) and object co-occurrence (dogs often near grass) trip up models. Modern approaches use vision-language models like CLIP or specialized VQA architectures.', 'VQA powers accessibility features, search-by-query on images, and interactive image understanding apps.', 'Typically a vision encoder + language model bridged by a fusion mechanism; training requires paired image-question-answer data.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('vqa', 'VQA', '', '', ARRAY['VQA','visual QA']::text[], 'Core', 'Shorthand for visual question answering - the ability to answer questions posed in natural language about visual content.', 'Like the parlor game "I spy" - someone describes what they see, you guess what it is. VQA is the reverse: you see the image, you answer the description.', 'A VQA system shown a photo with people, trees, and a bench answers "Are there more people or trees?" or "What is the bench made of?"', '[]'::jsonb, 'VQA models encode images into visual feature maps, encode questions into embeddings, fuse them (often with attention), and decode an answer. Quality degrades when images are cluttered, questions are compositional (multi-step reasoning), or the model has never seen similar image-question pairs. Large vision-language models have reduced but not eliminated this.', 'Widely used in e-commerce (product questions), accessibility, and interactive AI interfaces.', 'Standard benchmark datasets: VQA v2, GQA. Metrics: accuracy (exact match), BLEU, CIDEr.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('sceneunderstanding', 'Scene Understanding', '', '', ARRAY['scene understanding','scene parsing','scene comprehension','image understanding']::text[], 'Rising', 'The ability to recognize objects, relationships, and spatial structure within an image to grasp what is happening.', 'Walking into a room and instantly knowing: theres a kitchen, people are cooking, the table is set for dinner. Your brain understands the scene.', 'A model sees a photo and knows "this is a beach scene with a surfer paddling toward waves at sunset." Another sees a meeting room and identifies the projector, whiteboard, and seated participants.', '[]'::jsonb, 'Scene understanding combines object detection (what things are present), semantic segmentation (pixel-level categories), spatial reasoning (how objects relate), and sometimes activity recognition (what is happening). Requires parsing both low-level features (edges, colors) and high-level semantics (activities, social roles). Graph neural networks and transformer-based vision models show promise.', 'Unlocks context-aware recommendations, smart image search, autonomous navigation, and interactive AI that understands the users environment.', 'Combines detection, segmentation, and reasoning. Benchmarks: ADE20K (scenes), Cityscapes (street scenes). Often requires fusion of multiple CV tasks.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('depthestimation', 'Depth Estimation', '', '', ARRAY['depth estimation','monocular depth','stereo depth','depth prediction']::text[], 'Rising', 'Inferring how far objects are from the camera - recovering 3D structure from a 2D image.', 'Humans use binocular vision and visual cues (perspective, shadows, blur) to judge distance. Depth estimation teaches machines to do the same from one image.', 'Given a single photo of a street, predict how far each building, car, and pedestrian is from the camera. Used in AR apps to place virtual objects correctly on real surfaces.', '[]'::jsonb, 'Monocular depth (single image) is underconstrained - many 3D configurations project to the same 2D image. Models learn statistical priors from training: familiar objects are certain sizes, surfaces follow typical slopes. Stereo depth uses two cameras and triangulation, which is more reliable but requires paired hardware. Combines photometric cues (shading, perspective) with learned priors. Photogrammetry and NeRF approaches also recover depth.', 'Enables AR/VR, robotics, autonomous vehicles, and 3D video editing.', 'Monocular: usually supervised with depth ground truth from LiDAR or structured light. Metrics: absolute relative error, RMSE. Benchmarks: NYU Depth v2, KITTI.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('poseestimation', 'Pose Estimation', '', '', ARRAY['pose estimation','body pose','joint detection','skeleton detection']::text[], 'Rising', 'Detecting the positions of joints (elbows, knees, etc.) or landmarks (eyes, nose) to infer the posture of a person or object.', 'Like marking the joints on a stick figure: head, shoulders, elbows, hips, knees. The model predicts where each joint is in the image.', 'A fitness app analyzes a video of a user doing squats, detecting their knee, hip, and ankle positions to check form. A game uses hand pose to track gesture controls.', '[]'::jsonb, 'Human pose estimation typically predicts 2D pixel coordinates (and confidence) for each joint. Some models also infer 3D coordinates or depth. Challenging because people occlude themselves, appear at different scales, and in different lighting. Modern approaches use heatmaps (saliency maps at each joint) or direct regression. Top-down (detect person first, then their joints) vs. bottom-up (detect all joints, then link them).', 'Powers fitness tracking, gesture control, animation from video, sports analytics, and accessibility interfaces.', 'Standard datasets: COCO (17 joints), OpenPose (25 joints). Metrics: OKS (object keypoint similarity). Models: OpenPose, HRNet, MediaPipe.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('facedetection', 'Face Detection', '', '', ARRAY['face detection','face localization','face finding','facial detection']::text[], 'Core', 'Finding where faces are in an image - typically returning bounding boxes around each face.', 'Scanning a group photo and circling where each person is before you say their name.', 'A camera app highlights everyones face with a blue box before snapping the photo. Social media software detects faces for auto-tagging. Security systems spot peoples faces in video streams.', '[]'::jsonb, 'Face detection is a localization task, distinct from face recognition (identifying who). Faces vary wildly in scale, pose (profile vs. frontal), lighting, occlusion (sunglasses, hair). Cascade classifiers (Haar, boosted) were fast but dated. Modern approaches: CNNs, RetinaNet, YOLOv3 fine-tuned on face data. Handles multiple faces, extreme angles, and occlusion but struggles in extreme lighting or crowds.', 'Essential for photo apps, privacy (blur faces), security, and any system that needs to find and act on people.', 'Datasets: WIDER Face (diverse), Pascal Face, AFW. Metrics: precision, recall, AP. Benchmarks vary by pose and lighting difficulty.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('imageclassification', 'Image Classification', '', '', ARRAY['image classification','image categorization','visual classification','object recognition']::text[], 'Core', 'Assigning an image to a category or class - is this a cat, dog, bird, or car?', 'Sorting photos into labeled folders: vacation, pets, work.', 'Upload a photo; the system says "This is a dog." Medical imaging: "This X-ray shows pneumonia." Satellite imagery: "This region is urban."', '[]'::jsonb, 'Foundational computer vision task. CNN features (trained on ImageNet or self-supervised) map images to class probabilities. Multi-class (one label per image) vs. multi-label (multiple labels). Transfer learning from pretrained models dominates because labeled data is expensive. Vision transformers and modern CNNs (EfficientNet, ResNet) achieve superhuman accuracy on benchmarks but still fail on distribution shift, adversarial perturbations, and rare classes.', 'Drives content moderation, product tagging, medical diagnosis, and countless automated decisions.', 'Benchmark: ImageNet (1000 classes). Metric: top-1 and top-5 accuracy. Modern models: Vision Transformer, ConvNeXt, ResNet-50.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('zeroshotclassification', 'Zero-Shot Classification', '', '', ARRAY['zero-shot classification','unseen classes','semantic generalization']::text[], 'Rising', 'Classifying images into categories the model has never seen during training - by reasoning about semantic relationships.', 'You know what a "dog" is and what "four-legged" means. Someone shows you a "dachshund" - youve never seen that breed, but you know its a four-legged dog.', 'CLIP is trained on image-caption pairs. You ask it to classify a photo as one of ["cat", "dog", "elephant"] without ever seeing those three labels in training. It maps the image to embeddings and compares to the class name embeddings.', '[]'::jsonb, 'Bridges the train-test gap by using semantic attributes or language. CLIP and similar models encode images and text into a shared embedding space; classification is a nearest-neighbor lookup. Works for unseen classes by leveraging language understanding. Limited by coverage of the text space and spurious correlations in the joint embedding.', 'Enables systems to classify novel categories without retraining - huge for scalability and rapid iteration.', 'Models: CLIP, Flamingo. Metrics: accuracy on held-out classes. Datasets test on unseen classes: ImageNet-21K variants.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('latentdiffusion', 'Latent Diffusion', '', '', ARRAY['latent diffusion','latent diffusion model','LDM','diffusion in latent space']::text[], 'Rising', 'A diffusion model that learns to denoise in a compressed "latent" space rather than raw pixels - much faster and cheaper.', 'Instead of sculpting a full-size marble statue from scratch, you carve a small clay model, then enlarge it. Latent diffusion works in the small space.', 'Stable Diffusion and DALL-E 2 use latent diffusion. You describe "a red bicycle in the rain" - the model denoises a compressed latent vector, then decodes it to a high-res image in seconds.', '[]'::jsonb, 'Standard diffusion adds noise to pixels; latent diffusion adds noise to latent codes (output of a VAE encoder). The autoencoder compresses images, drastically reducing compute (4-8x speedup). Denoising happens in latent space, then the decoder reconstructs pixels. Enables cheap, fast text-to-image. Trade-off: lossy compression can blur fine details, but empirically results are excellent. Usually paired with a text encoder (CLIP) and sometimes a classifier-free guidance mechanism.', 'Democratizes image generation - runs on consumer hardware, enables real-time interactive editing, powers creative applications.', 'Architecture: VAE (encoder/decoder) + diffusion UNet in latent space + optional text encoder. Training: ~500K A100-hours on image-caption pairs.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('noiseschedule', 'Noise Schedule', '', '', ARRAY['noise schedule','timestep schedule','beta schedule','noise level']::text[], 'Core', 'The sequence of noise levels added to (or removed from) an image during diffusion - how much to corrupt at each step.', 'A recipe: "First scatter a bit of flour (10% noise), then more (20% noise), then keep stirring. Now reverse: pour out flour, then a bit less."', 'A linear schedule: noise increases from 0 to 1 over 1000 steps. A cosine schedule: slow at first, accelerating in the middle. DDPM uses a specific b sequence.', '[]'::jsonb, 'The schedule (b0, b1, ..., bt) controls how much Gaussian noise is added at each step. Too fast: model never learns to denoise gradual changes. Too slow: needs many steps. Cosine and linear schedules are common. Variance schedule also affects training - whether the model predicts noise, the mean, or the variance. Choice impacts convergence speed and final quality. Recent work (EDM, v-prediction) shows better schedules and parameterizations.', 'Tuning the schedule speeds up generation (fewer steps) or improves quality (better learned schedule).', 'Typically defined by b values. Common: linear b in [0.0001, 0.02], cosine b in [0.0001, 0.02].', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('guidancescale', 'Guidance Scale', '', '', ARRAY['guidance scale','guidance weight','conditional strength','cfg scale']::text[], 'Core', 'A hyperparameter controlling how strongly the model follows a conditioning signal (like a text prompt) during generation.', 'Leash length: 0 = completely free dog (ignores you), 7 = dog paying attention, 15 = dog tugging hard (over-correcting).', 'In Stable Diffusion, guidance scale 7 balances creativity and prompt adherence. Scale 15 follows the prompt rigidly, producing bland or distorted outputs. Scale 0 ignores it entirely.', '[]'::jsonb, 'Classifier-free guidance blends unconditional and conditional denoising predictions: pred = pred_uncond + scale x (pred_cond - pred_uncond). Scale = 0 -> unconditional. Scale = 1 -> conditional. Scale > 1 -> over-emphasis of conditioning. High scales sharpen the prompt but can create artifacts (oversaturation, impossible geometry). Optimal scale depends on model, prompt complexity, and desired creativity-faithfulness tradeoff.', 'Lets users trade off between following their prompt precisely and creative variation.', 'Typical range: 7-15 for text-to-image. Experiment per model. Trade-off: scale vs. sample quality.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('classifierfreeguidance', 'Classifier-Free Guidance', '', '', ARRAY['classifier-free guidance','CFG','unconditional guidance']::text[], 'Rising', 'A technique to steer diffusion models toward a condition (like text) without training a separate classifier - by blending conditional and unconditional predictions.', 'Instead of hiring a critic to rank your sketches, you sketch two versions (one from imagination, one from description) and blend them.', 'During training, sometimes drop the text prompt (unconditional). At generation, predict both paths - with and without text - then interpolate. This nudges the model toward the text without an external model.', '[]'::jsonb, 'Classic guidance requires a separate trained classifier (expensive, adds latency). CFG trains with random prompt dropout, so the model learns unconditional generation. At inference, compute both: unconditional pred and conditional pred, then blend: final = uncond + scale x (cond - uncond). Introduced in GLIDE; now standard in Stable Diffusion and others. No extra model, simple, effective. Scale controls influence; high scale can over-flatten diversity.', 'Cheaper than training a classifier; enables real-time control without external dependencies.', 'Requires training with conditional dropout. At inference, two forward passes. Typical scale: 7-15.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('negativeprompt', 'Negative Prompt', '', '', ARRAY['negative prompt','negative prompting','what not to generate','exclusion prompt']::text[], 'Rising', 'Specifying what you dont want in a generated image - telling the model to avoid certain concepts or styles.', 'A restaurant order: "Ill have a burger, extra cheese. No pickles, no mustard." The "no" parts guide the chef.', '"A dog running, negative: blurry, low quality, deformed." "A sunset, negative: people, buildings, text."', '[]'::jsonb, 'Implemented via classifier-free guidance by steering away from the negative condition. If you want to avoid "blurry," compute pred_avoid_blurry and pred_blurry, then interpolate away: final = pred_avoid - scale x (pred_blurry - pred_avoid). Doesnt require training on negative prompts; just reframes guidance. Effective but sometimes over-corrects (oversaturation of details). Combined with positive prompts: balance both. Empirically improves coherence and reduces artifacts.', 'Lets users refine outputs without iterating - powerful for creative control.', 'Uses guidance formula with reversed interpolation. Works best with concrete descriptions (blurry, ugly) vs. abstract (bad).', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('imagetoimage', 'Image-to-Image', '', '', ARRAY['image-to-image','img2img']::text[], 'Rising', 'Transforming an input image into a new image following a text prompt or style - starting diffusion from a noisy version of the input.', 'Photoshop with AI: you have a photo, you describe a change, the AI repaints parts of it.', '"A photo of a dog" -> "A painting of the same dog in Van Gogh style." Or: a room photo -> "Make it Victorian-era furniture."', '[]'::jsonb, 'Instead of starting diffusion from pure noise, encode the input image and add noise to it, then denoise. Strength parameter controls how much the model respects the input: 0 = no change, 1 = ignore input, generate fresh. Enables in-painting, outpainting, custom transformations. Requires the image and text encoder; reuses pretrained models. Allows fine-grained local editing if you mask regions.', 'Powers generative editing tools (Photoshop AI, professional retouching).', 'Requires VAE encoder to compress input, then add noise in latent space. Strength = diffusion timestep fraction.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('styletransfer', 'Style Transfer', '', '', ARRAY['style transfer','neural style transfer','artistic style','style adaptation']::text[], 'Fading', 'Applying the artistic style of one image to the content of another - turning a photo into a painting in a chosen style.', 'Using Photoshop filters or art classes: the content (what) stays the same, but the presentation (how its painted) changes.', 'Photo of a dog -> painted in Van Gogh stylized starry night style. A landscape photo -> watercolor sketch.', '[]'::jsonb, 'Classic approach (Gatys et al.): Gram matrix matches (texture statistics) swap style while preserving content. Defined via feature activations of a pretrained CNN (VGG). Slow (per-image optimization) but artistic. Modern alternatives: feed-forward networks trained on specific styles (faster but less flexible), or diffusion-based approaches. Perceptual loss guides optimization. Trade-off between content fidelity and style strength.', 'Dated by generative models but still useful for targeted artistic effects.', 'Classic method: Gram loss + content loss via perceptual features. Modern: generative models + prompt engineering.', 'Multimodal', 30, ARRAY['seed','multimodal']::text[]),
  ('texturesynthesis', 'Texture Synthesis', '', '', ARRAY['texture synthesis','procedural texture','texture generation','pattern synthesis']::text[], 'Fading', 'Generating new, larger versions of a texture by learning its statistical patterns and extrapolating.', 'A piece of bark: from a small sample, you infer the full tree and generate more bark that looks consistent.', 'Input: a 64x64 fabric swatch. Output: a seamless 1024x1024 image of the same fabric. Or grass, waves, marble patterns.', '[]'::jsonb, 'Statistical methods (e.g., Markov random fields, graph cuts) match local neighborhoods. Neural approaches learn texture statistics via CNNs and feed-forward or diffusion models. Conditional generation via example patches. Quality degrades if the texture has large structures or orientations. Generative models (GANs, diffusion) now dominate. Increasingly replaced by diffusion-based in-painting.', 'Graphics and game development, but replaced by diffusion models for most use cases.', 'Classic: non-parametric sampling. Modern: conditional diffusion or feed-forward network trained on texture pairs.', 'Multimodal', 30, ARRAY['seed','multimodal']::text[]),
  ('frameinterpolation', 'Frame Interpolation', '', '', ARRAY['frame interpolation','motion interpolation','in-between frames','optical flow synthesis']::text[], 'Rising', 'Generating intermediate frames between two video frames to create smooth slow-motion or increase frame rate.', 'Flip-book animation: you draw frames 1 and 3, and fill in frame 2 to make it smooth.', 'A video at 30fps -> interpolate to 60fps or 120fps for slo-mo sports. A 2-frame clip -> generate 10 frames in between.', '[]'::jsonb, 'Requires predicting motion (optical flow) and synthesizing pixels. Challenges: occlusion (new areas becoming visible), disocclusion (disappearing areas), blur, and ambiguity (multiple plausible in-betweens). Modern methods: flow-based (predict motion, warp + inpaint) or learning-based end-to-end (RIFE, trained on large video datasets). Diffusion-based approaches emerging. Must preserve temporal coherence.', 'Powers video upsampling, slow-motion effects, frame rate conversion for streaming.', 'Datasets: Vimeo90K, YouTube, custom. Metric: PSNR, SSIM, perceptual loss. Models: RIFE, DAIN.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('opticalflow', 'Optical Flow', '', '', ARRAY['optical flow','motion field','motion vectors','scene flow']::text[], 'Core', 'Estimating the direction and speed of motion for each pixel - where objects are moving between consecutive frames.', 'Watching a stream: the water flows in certain directions. You trace how each droplet moves.', 'Two consecutive video frames: optical flow shows where each part of a moving car or person went.', '[]'::jsonb, 'Classic method: Lucas-Kanade (local patches, assumes constant motion), Horn-Schunck (global smoothness). Modern: deep learning - FlowNet, RAFT train end-to-end on synthetic (FlyingChairs) or real data (Sintel, KITTI). Challenges: occlusion, lighting changes, large displacements, reflective surfaces. Used in video compression, action recognition, video interpolation, and autonomous driving.', 'Enables video understanding, compression, and autonomous driving.', 'Benchmark: Sintel (artistic), KITTI (real-world). Metric: end-point error (EPE), average angular error. Models: RAFT, FlowNet2, PWCNet.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('audiogeneration', 'Audio Generation', '', '', ARRAY['audio generation','waveform generation','audio synthesis']::text[], 'Rising', 'Automatically creating sound or audio content from scratch or from a description.', 'A composer writing a melody - the model generates the notes and tones.', 'Text prompt: "Dog barking at distance" -> generated audio of a dog bark. Or: "Electronic lo-fi hip-hop beat" - the model produces the music.', '[]'::jsonb, 'Raw waveform generation (difficult, high-dimensional) vs. spectrogram generation (compact, then vocoded back). Autoregressive (SampleRNN, WaveNet) vs. non-autoregressive (FastSpeech, diffusion). Text-to-speech, music generation, and sound effect synthesis use different architectures. Transformer-based models and diffusion models show promise. Challenge: long-range coherence, realistic timbre, and diversity.', 'Enables text-to-speech, generative music, game sound design, accessibility, content creation.', 'Architectures: Diffusion models (Riffusion, MusicGen), autoregressive transformers. Datasets: AudioSet, FSD50K. Metrics: mel-cepstral distortion (MCD), log-magnitude RMSE.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('musicgeneration', 'Music Generation', '', '', ARRAY['music generation','automatic composition','generative music','melody generation']::text[], 'Rising', 'Creating original musical compositions - melodies, harmonies, or full arrangements - often from text or other constraints.', 'A composer jamming: they start with a mood or theme and improvise the rest.', 'Text: "Upbeat electronic dance music in minor key" -> model generates a full track. Or: MIDI prompt -> extend or remix it.', '[]'::jsonb, 'Can operate on symbolic level (MIDI, musical notation) or audio (waveforms, spectrograms). Symbolic: discrete tokens, easier to learn long-form structure, less data needed, but limited expressiveness. Audio: richer, but harder to train and slower. Transformer-based models (e.g., Jukebox), diffusion models (Riffusion), and VAE-based approaches. Challenges: long-range structure (songs have verse-chorus), coherence, diversity, and domain specificity (different genres).', 'Accelerates music production, enables personalized content, supports creators.', 'Datasets: Spotify, MAESTRO (MIDI), FSD50K. Metrics: musicality, adherence to prompt, diversity. Models: MusicGen, Jukebox.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('soundeffectgeneration', 'Sound Effect Generation', '', '', ARRAY['sound effect generation','SFX generation','foley synthesis']::text[], 'Rising', 'Automatically creating sound effects for games, films, or other media - from descriptions or input parameters.', 'A Foley artist in a film studio creating sounds by hand; the model does it digitally.', 'Text: "Glass breaking, high-pitched, with echo" -> generates a plausible glass-breaking sound. Or: parameter tuning for "footstep volume and surface material".', '[]'::jsonb, 'Usually text-to-audio (e.g., AudioLDM trained on text-sound pairs from AudioSet). Operates on spectrograms (STFT) or raw waveforms. Challenges: specificity (descriptions vary widely), rare events (uncommon sounds have little training data), realism (artifacts, phase coherence). Diffusion-based approaches (latent diffusion in spectrogram space) show good results. Used in games (dynamic SFX) and film post-production.', 'Drastically speeds up game and film production; enables real-time sound design.', 'Text-to-audio diffusion models. Datasets: AudioSet, Freesound, FSD50K. Evaluation: subjective listening tests, acoustic feature matching.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('speakerdiarization', 'Speaker Diarization', '', '', ARRAY['speaker diarization','speaker segmentation','who spoke when','speaker attribution']::text[], 'Rising', 'Identifying and separating who spoke when in an audio recording - marking "Speaker A: [0:00-1:23], Speaker B: [1:24-3:00]."', 'Reading a script with multiple characters and labeling which character speaks each line.', 'A meeting recording: the system marks "Alice: 0:00-1:30, Bob: 1:31-2:15, Alice: 2:16-3:00."', '[]'::jsonb, 'Combines voice activity detection (is anyone speaking?), voice embedding extraction (speaker signature per segment), and clustering (group similar speakers). Assumes a speaker has consistent acoustic characteristics. Challenges: similar voices, overlapping speech, channel differences, long recordings (speaker drift). Typically: extract speaker embeddings (x-vector, d-vector), run clustering (spectral, agglomerative). Recent: end-to-end differentiable models (PyAnnote, ECAPA-TDNN).', 'Essential for meeting transcripts, podcast chapters, media indexing, and accessibility.', 'Datasets: AMI, ICSI. Metrics: diarization error rate (DER), composed of miss, false alarm, and speaker confusion. Models: x-vector, ECAPA-TDNN.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('phoneme', 'Phoneme', '', '', ARRAY['phoneme','speech unit','sound unit','distinctive sound']::text[], 'Core', 'The smallest unit of sound in language that distinguishes meaning - like /p/ and /b/ in "pat" vs. "bat."', 'In English, letters; in speech, phonemes. Phones (sounds) are instances; phonemes are categories.', 'English: "cat" = /k/ /a/ /t/ (3 phonemes). "ship" = /sh/ /i/ /p/ (3 phonemes). "thought" = /th/ /o/ /t/ (3 phonemes).', '[]'::jsonb, 'Language-specific inventory. English ~= 44 phonemes; Spanish ~= 24. Recognition: acoustic models predict phonemes from spectrograms (Gaussian mixtures, DNNs, HMMs). Text-to-speech needs phoneme-level alignment. CTC loss (Connectionist Temporal Classification) allows direct acoustic-to-phoneme without explicit alignment.', 'Core for speech recognition, TTS, and language learning apps.', 'Datasets: TIMIT (phoneme labels). Metrics: phoneme error rate (PER). Models: acoustic models trained with HMMs or CTC.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('melspectrogram', 'Mel Spectrogram', '', '', ARRAY['mel spectrogram','mel-scale spectrogram','mel-frequency spectrogram']::text[], 'Core', 'A spectrogram where frequencies are warped to the mel scale - which better matches human hearing than linear frequency.', 'A piano keyboard: low keys are spaced widely (low frequencies), high keys are spaced closely (we hear pitch logarithmically).', 'Raw spectrogram: 0-22050 Hz linearly. Mel spectrogram: frequencies warped so differences we actually perceive are evenly spaced.', '[]'::jsonb, 'Humans perceive pitch logarithmically, not linearly. Mel scale (0-2595 mels) mimics this. Transform: take STFT magnitude, apply triangular filterbank on mel scale, take log (perceptual weighting). Smaller, more interpretable than raw spectrograms. Used as input to speech recognition, music tagging, audio classification. Variants: MFCC (adds DCT, compresses further). Provides good frequency resolution for speech and music.', 'Standard input representation for audio models - improves performance and reduces data size.', 'Convert waveform -> STFT -> power spectrum -> mel-scale filterbank -> log compression. Libraries: librosa, scipy.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('vocoder', 'Vocoder', '', '', ARRAY['vocoder','neural vocoder','spectrogram-to-speech','waveform synthesis']::text[], 'Rising', 'A model that converts a spectrogram or other audio representation into a waveform - turning abstract audio features into actual sound.', 'A printer for sound: you describe the pattern (spectrogram), and the printer produces the actual sound waves.', 'Text-to-speech pipeline: text -> phonemes -> mel-spectrogram (Tacotron) -> waveform (vocoder like WaveGlow or HiFi-GAN).', '[]'::jsonb, 'Spectrograms compress audio (lose phase, time resolution), but humans need waveforms to hear. Vocoders reconstruct waveforms from spectrograms. Early: Griffin-Lim (heuristic, low quality). Modern: WaveNet (autoregressive, high quality, slow), WaveGlow (flow-based, fast), HiFi-GAN (GAN-based, fastest and best quality). Challenges: phase reconstruction, generalization to unseen speakers, real-time synthesis.', 'Critical for TTS quality; faster vocoders enable real-time speech synthesis on mobile.', 'Input: mel-spectrogram. Output: 16 or 24 kHz waveform. Models: HiFi-GAN, WaveGlow, Glow-TTS. Metric: MOS (Mean Opinion Score).', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('lipsync', 'Lip Sync', '', '', ARRAY['lip sync','lip-sync','audio-visual alignment','speech sync']::text[], 'Rising', 'Aligning a video of mouth movements with audio - or generating video that matches audio.', 'Dubbing: the actors lips must match the audio dialogue.', 'A talking head avatar syncs its mouth to generated speech. A video with mismatched audio is corrected.', '[]'::jsonb, 'Can mean: (1) verifying alignment (is this video dubbed?), or (2) generating video frames of a mouth matched to audio. Deterministic: use detected lip keypoints + audio to measure sync loss. Generative: audio -> visual features -> video frames (requires autoregressive or diffusion model). Challenges: accents, realistic teeth/tongue, avoiding uncanny valley.', 'Powers deepfakes, talking-head avatars, audiobook video, and dubbed content.', 'Audio-video alignment loss: sync between phoneme onsets and mouth movements. Generative: condition on audio embeddings, generate frame sequences.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('talkinghead', 'Talking Head', '', '', ARRAY['talking head','talking avatar','animated avatar','speech-driven animation']::text[], 'Rising', 'An animated face or avatar that moves its mouth and head to match speech - creating the illusion of someone talking.', 'A puppet master animating a doll to lip-sync.', 'Given a portrait photo and speech audio, generate a video of the face talking naturally.', '[]'::jsonb, 'Input: single image + audio. Output: video of that person talking. Requires: (1) lip-sync, (2) head pose/gaze matching content, (3) realistic motion. Methods: keypoint-based (detect facial landmarks, animate), flow-based (predict motion fields), or diffusion (generate frames autoregressively or in latent space). Challenges: convincingness (uncanny valley), preserving identity, handling out-of-domain audio (accents, singing). Models like Wav2Lip, Metaface, or diffusion-based approaches.', 'Enables virtual presenters, customer service bots, personalized video messages.', 'Input: still image + audio. Output: video. Lip-sync critical. Benchmarks: LRS3 (audio-video pairs). Metrics: sync accuracy, visual quality (LPIPS, FID).', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('avatargeneration', 'Avatar Generation', '', '', ARRAY['avatar generation','character synthesis','digital avatar','virtual character']::text[], 'Rising', 'Creating a digital character or persona - either from text description or by personalizing a template.', 'Character design: an artist sketches a character; the model generates a 3D or 2D avatar automatically.', '"A professional woman, brown hair, glasses, smiling" - generates a realistic avatar. Or: input a photo -> generates anime-style version of that person.', '[]'::jsonb, '2D (image, video) vs. 3D (mesh, point cloud). Text-to-avatar: generate image/model from prompt. Photo-to-avatar: style transfer or 3D reconstruction. Challenges: identity preservation, realism, animation (can the avatar move naturally?). Methods: GANs, diffusion models, NeRF for 3D. Real-time avatars (gaming) vs. high-quality offline (cinema).', 'Powers gaming, metaverse, virtual events, and personalized digital representations.', '2D: text-to-image + style transfer. 3D: text-to-3D (NeRF, diffusion) or photogrammetry. Models: DreamFusion.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('3dgeneration', '3D Generation', '', '', ARRAY['3D generation','text-to-3D','3D synthesis','generative 3D']::text[], 'Rising', 'Creating 3D models - meshes, point clouds, or implicit representations - from text, images, or other inputs.', 'Sculpting: a 2D sketch or description -> a 3D form.', '"A wooden chair, modern design" - generates a textured 3D model. Or: a 2D image -> 3D reconstruction.', '[]'::jsonb, 'Text-to-3D: use pre-trained 2D diffusion (e.g., Stable Diffusion) to score candidate 3D models (NeRF, mesh), optimize via SDS (score distillation sampling). Single-image 3D: depth estimation + shape completion. Challenges: slow (many iterations), unrealistic fine details, lighting ambiguity. Implicit representations (NeRF) vs. explicit (meshes). Recent: diffusion models directly in 3D space (e.g., 3D diffusion models).', 'Accelerates game art, architecture visualization, e-commerce product renders.', 'Methods: NeRF + SDS loss, diffusion-based, flow-based. Representations: mesh, voxels, point cloud, SDF, implicit neural fields.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('nerf', 'NeRF', '', '', ARRAY['NeRF','neural radiance field','implicit neural representation','radiance field']::text[], 'Rising', 'A neural network that represents a 3D scene by learning to predict color and density for any ray direction through space.', 'Instead of storing a 3D mesh or voxel grid, you have a function: "Give me a ray, Ill tell you what color and density it sees."', 'Input: multiple photos of a sculpture from different angles. NeRF learns to synthesize any novel viewpoint, rendering high-quality new photos.', '[]'::jsonb, 'Encodes 3D space as a function: f(x, y, z, theta, phi) -> (r, g, b, sigma). Positional encoding (Fourier features) maps coordinates into high-dimensional space for better learning. Volume rendering integrates along rays (standard differentiable raycasting). Training: minimize photometric loss on input views. Advantages: compact, high quality, no mesh topology. Disadvantages: slow rendering (1-100s per frame), tricky optimization, requires many input views.', 'Novel view synthesis, 3D reconstruction, VR/AR content creation.', 'Input: multi-view images + camera poses. Output: implicit 3D representation rendering any viewpoint. Metric: PSNR, LPIPS, SSIM.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('gaussiansplatting', 'Gaussian Splatting', '', '', ARRAY['Gaussian splatting','Gaussian splats','3D Gaussian splatting','3DGS']::text[], 'Rising', 'Representing a 3D scene as a cloud of colored, oriented Gaussians - efficient rendering of novel views.', 'Instead of tracing rays, you paint with blurry paint drops (Gaussians) positioned in 3D space.', 'Multi-view photos -> optimize Gaussian positions, colors, covariance -> render novel viewpoints in real-time.', '[]'::jsonb, 'Each Gaussian: center, covariance (orientation/scale), color. Volume rendering sums contributions along each ray. Differentiable rasterization enables optimization. Much faster than NeRF (10-100x speedup), real-time quality, fewer views needed. Trade-off: requires careful initialization (SfM points or coarse NeRF), can have artifacts (floaters, oversplatting). Emerging as practical alternative to NeRF.', 'Real-time 3D rendering, VR/AR, game engines, streaming 3D content.', 'Differentiable splatting + sorting-based rendering. Faster than NeRF. Requires CUDA. Metric: same as NeRF (PSNR, LPIPS).', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('pointcloud', 'Point Cloud', '', '', ARRAY['point cloud','point set','3D points','LiDAR cloud']::text[], 'Rising', 'A set of 3D points representing the surface or volume of an object or scene - alternative to meshes or voxels.', 'A cloud of dots in 3D space, each a measurement of a surface.', 'LiDAR scan of a street: millions of points, each with (x, y, z) and optionally color or intensity. A object scan: 50K points on a statue.', '[]'::jsonb, 'Unstructured, no topology requirement (unlike meshes). Can be large (millions of points). Advantages: simple representation, no adjacency constraints, natural from sensors (LiDAR, depth cameras). Disadvantages: noisy, sparse, rendering/processing is non-trivial. ML on point clouds: PointNet (permutation invariant), PointNet++, Point Transformer. Applications: 3D object recognition, segmentation, tracking, autonomous driving.', 'Autonomous vehicles, 3D imaging, scene understanding.', 'Representation: (N, 3) array of x, y, z or (N, 6) with colors. Processing: PointNet-based architectures. Metric: Chamfer distance, Hausdorff distance.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('meshgeneration', 'Mesh Generation', '', '', ARRAY['mesh generation','mesh synthesis','3D mesh generation','geometry generation']::text[], 'Rising', 'Creating a 3D mesh - vertices, edges, and faces - from text, images, or point clouds.', 'Sculpting: starting with clay (text description or image), carving it into a shape with faces and edges.', '"A ceramic mug" -> generates a mesh with proper handle, rim, interior. Or: single photo -> mesh of that object.', '[]'::jsonb, 'Meshes are topologically fixed (cant easily change vertex count). Methods: predict vertex coordinates, predict which vertices connect (graph), or start with a template mesh and deform it. Text-to-3D often generates NeRF or point cloud, then extracts mesh via marching cubes. Single-image: depth + shape completion. Challenges: non-manifold geometry (mismatched topology), self-intersections. Explicit meshes are artist-friendly but hard to generate. Implicit (signed distance functions, occupancy) are easier to learn, harder to render.', 'Game art, 3D printing, CAD augmentation.', 'Marching cubes, Poisson surface reconstruction, or learned mesh deformation. Metric: Chamfer distance, F-score (geometric accuracy).', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('videounderstanding', 'Video Understanding', '', '', ARRAY['video understanding','video analysis','action understanding','event recognition']::text[], 'Rising', 'Comprehending what is happening in a video - recognizing actions, events, and relationships across frames.', 'Watching a film: you understand the plot, characters, emotions, and story arc, not just individual shots.', 'A video of a person doing yoga: the system identifies the pose, flow, difficulty. A traffic accident video: identifies vehicles, speeds, impact.', '[]'::jsonb, 'Combines spatial (per-frame image understanding) and temporal (across frames) reasoning. Motion (optical flow, 3D convolutions) matters. Challenges: long-range dependencies (plot of a 2-hour film), background clutter, unusual viewpoints. Models: 3D CNNs (C3D, I3D), transformer-based (ViT + temporal), two-stream (spatial + temporal). Fine-grained understanding requires long-context attention, multimodal grounding (audio, subtitles).', 'Content moderation, action recognition for sports/fitness, video search, autonomous driving.', 'Datasets: UCF-101, Kinetics-400, ActivityNet. Metrics: top-1 accuracy, F-score. Models: I3D, TimeSformer.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('actionrecognition', 'Action Recognition', '', '', ARRAY['action recognition','activity recognition','gesture recognition','skeletal action']::text[], 'Core', 'Identifying what action or activity a person is performing in video or from skeleton keypoints.', 'Watching an athlete and saying "she is doing a cartwheel" or "he is shooting a basketball."', 'Video of person doing: jumping jack -> identified. Skeleton pose: arms up, legs spread -> jumping jack.', '[]'::jsonb, 'Appearance-based: use RGB frames (3D CNN, optical flow). Skeleton-based: use pose keypoints (graph conv, temporal conv). Skeleton methods are faster and more interpretable but require accurate pose estimation. Challenges: subtle actions (whispering vs. talking), view-invariance (different angles), fine-grained (kick vs. jump). Temporal modeling (RNN, transformer, temporal convolution) crucial. Large datasets (Kinetics) improved performance.', 'Fitness tracking, sports analytics, gaming, accessibility (gesture control).', 'RGB-based: I3D, SlowFast. Skeleton-based: ST-GCN, Shift-GCN. Datasets: Kinetics-400, NTU RGB+D. Metric: top-1 accuracy.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('temporalmodeling', 'Temporal Modeling', '', '', ARRAY['temporal modeling','temporal reasoning','sequence modeling','time-aware learning']::text[], 'Core', 'Learning patterns across time - understanding how things change frame-to-frame or over longer sequences.', 'Reading a book page-by-page, understanding not just the words on one page but the story across chapters.', 'In video: a persons hand position at frame 5 predicts frame 6. In trajectories: car position at time t predicts time t+1.', '[]'::jsonb, 'RNNs/LSTMs for sequential processing. Temporal convolutions (dilated, 1D) for parallel processing. Transformers for long-range dependencies (self-attention across time). 3D convolutions (C3D, I3D) combine spatial-temporal. Optical flow captures explicit motion. Challenges: long sequences (slow, memory), long-term dependencies (vanishing gradients), diverse temporal scales (slow burn to fast action). Contrastive learning (temporal augmentation) improves models.', 'Video understanding, prediction, forecasting, anomaly detection.', 'Temporal convolution, recurrence, or attention. Positional encoding for time. Metric: depends on task (action classification, prediction accuracy).', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('multimodalfusion', 'Multimodal Fusion', '', '', ARRAY['multimodal fusion','modality fusion','cross-modal fusion','fusion strategy']::text[], 'Core', 'Combining information from multiple modalities (text, image, audio) to make a joint prediction or representation.', 'A deaf person reads captions while watching a video; a hearing person listens to audio. Both together understand better.', 'Text "dog" + image of a dog -> stronger confidence that its a dog. Video frame + audio -> identify the action better.', '[]'::jsonb, 'Fusion can happen early (raw signals), mid (embeddings), or late (predictions). Early: mix modalities before processing. Mid: project each modality to shared space, combine. Late: predict separately, then ensemble. Alignment is crucial: align embeddings so related content (matching image-text pairs) is close. Challenges: missing modalities, domain gap, temporal/spatial alignment. Methods: dot-product attention, cross-attention, learned fusion networks, or contrastive objectives (like CLIP).', 'Multimodal search (text + image query), accessible systems, robust recommendations.', 'Fusion strategies: concatenation, element-wise, attention-based, learned gates. Alignment: contrastive loss or reconstruction loss.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('earlyfusion', 'Early Fusion', '', '', ARRAY['early fusion','input fusion','raw fusion','concatenated input']::text[], 'Rising', 'Combining raw data from multiple modalities before any processing - concatenating inputs and processing jointly.', 'Mixing all ingredients at the start of cooking, then heating together.', 'Text tokens + image patches -> concatenate and feed to transformer. Audio waveform + visual frames -> joint processing.', '[]'::jsonb, 'Pro: joint optimization from the start, exploits cross-modal correlations early. Con: modalities have different dimensionality, noise, and temporal alignment issues; early concatenation may not work well. Requires careful preprocessing (time-syncing audio/video, resizing images). Good when modalities are naturally aligned (e.g., talking head: audio + video frames are synchronized).', 'Works well when modalities are perfectly synchronized; simpler architecture.', 'Concatenate features, process with shared backbone (CNN, transformer). Challenge: balancing modality sizes and rates.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('latefusion', 'Late Fusion', '', '', ARRAY['late fusion','output fusion','decision fusion','ensemble fusion']::text[], 'Core', 'Processing each modality separately, then combining predictions or embeddings - learn each independently, then fuse.', 'Each person reads the summary alone, then they discuss and agree on the interpretation.', 'Image classifier outputs "dog (0.9)" and text classifier outputs "dog (0.8)" -> ensemble: average to 0.85.', '[]'::jsonb, 'Pro: modalities processed independently (easier debugging, transfer learning), robust to missing modalities (can skip one branch). Con: misses early cross-modal cues, duplicates computation. Typically: separate encoders per modality, combine embeddings or predictions. Fusion can be: averaging, attention-based, gated, or learned weights.', 'Flexible, handles missing modalities, easier to debug.', 'Separate encoders, then fusion layer (attention, gating, or simple averaging). Metric: depends on task.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('crossattentionfusion', 'Cross-Attention Fusion', '', '', ARRAY['cross-attention fusion','cross-modal attention','modality attention']::text[], 'Rising', 'Using attention to let one modality query another - "which parts of the image are relevant to this text?" - enabling fine-grained fusion.', 'You read a question, then scan the image to find the most relevant parts, then reason over those.', 'VQA: text query "Where is the dog?" attends to image regions; high attention to dog area, low to background.', '[]'::jsonb, 'Query modality attends to key/value modality: Attention(Q_text, K_image, V_image). Enables asymmetric interaction (text queries image, or vice versa). Multi-head attention captures different query-image relationships. Can stack (iterative cross-attention) for refinement. Widely used in CLIP, BLIP, ViLBERT. More flexible than early/late fusion, captures fine-grained alignment.', 'More accurate multimodal understanding; enables interpretability (which image regions matter).', 'Implement with multi-head cross-attention. Typical: text queries image (or vice versa). Bidirectional: both query each other.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('visiontransformer', 'Vision Transformer', '', '', ARRAY['vision transformer','image transformer']::text[], 'Rising', 'A transformer architecture applied to images, treating image patches as tokens - enabling pure attention-based vision.', 'Like BERT for text, but for images: split image into patches, embed them, apply self-attention.', 'Split a 224x224 image into 16x16 patches (196 patches), embed each, run transformer. Classification: use [CLS] tokens final hidden state.', '[]'::jsonb, 'Key insight: transformers dont inherently understand locality; they learn it. But they excel at global context and long-range dependencies. ViT requires many images to train (ImageNet alone is insufficient; needs 14M images or pre-training tricks). Patch size trade-off: large patches = fewer tokens (faster), small patches = more tokens (richer). Hybrid (CNN backbone -> patches to transformer) is also common. Recent: efficient variants (DeIT, DeiT-III), multi-scale (Swin Transformer).', 'Versatile backbone for vision tasks; scales to large models (foundation models).', 'Input: image -> patches -> embed -> transformer blocks -> classification head. Metric: ImageNet top-1 accuracy. Models: ViT-B/16, ViT-L/16, Swin.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('vit', 'ViT', '', '', ARRAY['ViT']::text[], 'Rising', 'Shorthand for Vision Transformer - a transformer model for image understanding.', 'BERT is ViTs sibling: BERT processes text, ViT processes images.', 'ViT-Base trained on ImageNet; can be fine-tuned on medical imaging, COCO, or used as a backbone for other tasks.', '[]'::jsonb, 'Canonical form: ViT splits images into 16x16 patches (patch size P), embeds them (D dimensions), then runs 12-24 transformer blocks. Position encoding is learned (2D). Classification uses a learnable [CLS] token (like BERT). Requires large-scale pre-training; fine-tuning on small datasets underperforms CNNs. But pre-trained on large data (ImageNet-21K, JFT-300M), ViT outperforms CNNs and scales better to larger models.', 'Strong baseline for multimodal models (CLIP combines ViT image encoder with text transformer).', 'Architecture: N patches of D dim, transformer. Training: supervised on ImageNet-21K or self-supervised (MAE, DINO). Metric: ImageNet top-1 accuracy.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('patchembedding', 'Patch Embedding', '', '', ARRAY['patch embedding','patch projection','patch tokenization','image patches']::text[], 'Core', 'Dividing an image into small patches and embedding each patch into a vector - the first step of Vision Transformer.', 'Breaking a large poster into tiles; each tile is then scanned and digitized.', 'A 224x224 image with 16x16 patch size = 14x14 = 196 patches. Each patch is a 3x256 vector (16x16x3 = 768 dims flattened, then linearly projected to D).', '[]'::jsonb, 'Linear projection (conv 1x1) or learned embeddings map each patch to embedding dimension. Positional encoding added (learned, absolute, or relative). Trade-off: large patches = fewer tokens (efficient), small patches = more tokens (finer granularity). Patches of 14x14 or 16x16 are common. No CNN inductive bias; transformer learns locality from data.', 'Enables transformer-based vision, scalable to large models.', 'Implementation: reshape, linear projection, add positional embeddings. Typical: 768-2048 D, 196-576 patches.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('imagetokenization', 'Image Tokenization', '', '', ARRAY['image tokenization','image discretization','visual tokens','image coding']::text[], 'Rising', 'Converting an image into discrete tokens - like text tokenization - enabling language models to process images as sequences.', 'Text is tokenized ("hello" -> [hello, world]); images can be tokenized (image -> [token_1, token_2, ...]).', 'Codebook-based (VQ-VAE): image -> latent codes, each code maps to a vector in a learned codebook. BPE-based: image -> visual tokens via hierarchical clustering.', '[]'::jsonb, 'Vector quantization (VQ-VAE, VQ-GAN) learns a discrete codebook; images are encoded, quantized to nearest codebook entries, then decoded. Enables autoregressive generation (predict tokens sequentially). Alternative: DALL-E uses BPE-like tokenization on learned visual features. Advantage: unified text-image processing (same transformer). Disadvantage: lossy compression, training overhead.', 'Enables unified text-image models (autoregressive image generation).', 'VQ-VAE: encoder -> codebook lookup -> decoder. Codebook size: 2^k entries (e.g., 8192). Metric: reconstruction quality (LPIPS).', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('visualgrounding', 'Visual Grounding', '', '', ARRAY['visual grounding','image grounding','phrase grounding']::text[], 'Rising', 'Locating which region of an image a text phrase refers to - bridging language and vision.', 'Someone says "the red car on the left," and you point to it in the picture.', '"The dog wearing a hat" -> system highlights the bounding box or segment of the dog wearing a hat in the image.', '[]'::jsonb, 'Related to: VQA (answer question), referring expression (find object from description). Requires fine-grained alignment of text and image regions. Methods: detection-based (find all objects, match to phrases), alignment-based (compute attention of phrases to image regions). Challenges: compositional phrases ("red dog" is red + dog), ambiguity (multiple matching regions), rare objects.', 'Accessible search ("show me the person on the right"), interactive editing, multimodal retrieval.', 'Input: image + text phrase. Output: bounding box or segmentation mask. Datasets: Flickr30K, ReferIt, RefCOCO. Metric: Intersection over Union (IoU).', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('referringexpression', 'Referring Expression', '', '', ARRAY['referring expression','referring expression comprehension','visual reference','object reference']::text[], 'Rising', 'Understanding language that refers to specific objects in an image - "the woman in the red hat on the left."', 'In a crowded photo: "the person in the back row, third from the left."', '"The tallest building" -> output: bounding box of the tallest building in the image.', '[]'::jsonb, 'Comprehension task: given phrase, find object. Generation task: describe an object so someone can identify it. Comprehension requires grounding (localization). Generation requires visual understanding + language fluency. Compositional phrases ("red car" = red + car) and relational ("to the left of the dog") are challenging. Transformer-based models with cross-attention excel.', 'Accessible systems, interactive retrieval, visual question answering.', 'Comprehension: image + text -> bounding box/mask. Generation: image + bounding box -> description. Datasets: Flickr30K, ReferCOCO. Metric: accuracy, IoU.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('imageediting', 'Image Editing', '', '', ARRAY['image editing','inpainting','guided editing']::text[], 'Rising', 'Modifying an image by describing changes in natural language - remove an object, change a color, add elements.', 'Photoshop but with text instructions: "remove the sign" instead of using the eraser tool.', '"A cat wearing sunglasses" -> modify the original cat photo to add sunglasses. "Change the sky to purple" -> repaints the sky.', '[]'::jsonb, 'Inpainting: mask the region to edit, then diffusion fills it. Guided editing: text-guided diffusion + masking. Challenges: semantic consistency (edited region matches surroundings), identity preservation (original object recognizable). Methods: diffusion + mask, optimization-based (LPIPS loss), or learned editing networks. Requires careful balance of adherence to prompt vs. realism.', 'Consumer photo editing, professional retouching, content creation.', 'Text encoder + image encoder + diffusion UNet + masking. Loss: reconstruction (original) + guidance (text).', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('instancesegmentation', 'Instance Segmentation', '', '', ARRAY['instance segmentation','object instance segmentation','individual object segmentation']::text[], 'Core', 'Identifying each distinct object and outlining its pixels - distinguishing "dog 1," "dog 2," etc., not just "dog."', 'Semantic segmentation colors all dogs red; instance segmentation outlines each dog separately.', 'A photo of three dogs: semantic segmentation marks all dog pixels. Instance segmentation outlines each dog separately (dog #1, dog #2, dog #3).', '[]'::jsonb, 'Combines object detection (bounding box per object) and semantic segmentation (per-pixel labeling). Typically two-stage: Faster R-CNN for boxes, then mask prediction in each box (Mask R-CNN). One-stage alternatives: YOLACT, CondInst. Challenges: dense predictions on high-res images (slow), overlapping objects (which pixels belong to which?), rare categories.', 'Autonomous vehicles, medical imaging (individual organ segmentation), robot manipulation.', 'Mask R-CNN: Faster R-CNN + mask branch. Datasets: COCO (80 classes). Metric: Average Precision at IoU=0.5 and 0.75, Average Recall.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('panopticsegmentation', 'Panoptic Segmentation', '', '', ARRAY['panoptic segmentation','panoptic','unified segmentation','stuff and things']::text[], 'Rising', 'Segmenting an image into both "things" (countable objects like people) and "stuff" (uncountable regions like grass) with instance-level labels for things.', '"Things": individual cars, people. "Stuff": road, sky, grass. Panoptic labels each car and person individually, but groups all sky pixels together.', 'A street scene: panoptic segmentation labels each car (instance 1, 2, 3...), each person, but groups all road pixels.', '[]'::jsonb, 'Unifies instance segmentation ("things") and semantic segmentation ("stuff"). Requires: detection + instance masks for things, dense segmentation for stuff. Metric: Panoptic Quality (PQ) = segmentation quality + recognition quality. Challenges: class imbalance (many road pixels, few people), high resolution (computational cost), ambiguous boundaries.', 'Scene understanding, autonomous driving, robotics.', 'Architecture: instance + semantic branches, combine outputs. Datasets: COCO panoptic, ADE20K. Metric: PQ, thresholds on IoU.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[])
